//! Futex implementation.

use core::ops::Deref;

use alloc::{collections::btree_map::BTreeMap, sync::Arc};
use axsync::Mutex;
use axtask::{TaskExtRef, WaitQueue, current};

/// A table mapping memory addresses to futex wait queues.
pub struct FutexTable(Mutex<BTreeMap<usize, Arc<WaitQueue>>>);
impl FutexTable {
    /// Creates a new `FutexTable`.
    pub fn new() -> Self {
        Self(Mutex::new(BTreeMap::new()))
    }

    /// Gets the wait queue associated with the given address.
    pub fn get(&self, addr: usize) -> Option<WaitQueueGuard> {
        let wq = self.0.lock().get(&addr).cloned()?;
        Some(WaitQueueGuard {
            key: addr,
            inner: wq,
        })
    }

    /// Gets the wait queue associated with the given address, or inserts a a
    /// new one if it doesn't exist.
    pub fn get_or_insert(&self, addr: usize) -> WaitQueueGuard {
        let mut table = self.0.lock();
        let wq = table
            .entry(addr)
            .or_insert_with(|| Arc::new(WaitQueue::new()));
        WaitQueueGuard {
            key: addr,
            inner: wq.clone(),
        }
    }
}

#[doc(hidden)]
pub struct WaitQueueGuard {
    key: usize,
    inner: Arc<WaitQueue>,
}
impl Deref for WaitQueueGuard {
    type Target = Arc<WaitQueue>;

    fn deref(&self) -> &Self::Target {
        &self.inner
    }
}
impl Drop for WaitQueueGuard {
    fn drop(&mut self) {
        let curr = current();
        let mut table = curr.task_ext().process_data().futex_table.0.lock();
        if Arc::strong_count(&self.inner) == 1 && self.inner.is_empty() {
            table.remove(&self.key);
        }
    }
}

//! System V shared memory implementation for Neon-OS.
//!
//! This module provides System V shared memory IPC support including:
//! - Shared memory segment management with automatic cleanup
//! - Per-process shared memory tracking  
//! - Secure ID allocation with collision detection
//! - Linux-compatible permissions and error handling

use alloc::collections::BTreeMap;
use alloc::sync::Arc;
use axalloc::global_allocator;
use axerrno::{AxError, AxResult};
use axhal::mem::{PAGE_SIZE_4K, virt_to_phys};
use axsync::Mutex;
use axtask::{TaskExtRef, current};
use core::sync::atomic::AtomicBool;
use lazy_static::lazy_static;
use memory_addr::{PhysAddr, VirtAddr, align_up_4k};

/// Shared memory segment identifier.
pub type ShmId = i32;

/// Shared memory key.
pub type ShmKey = i32;

/// IPC_PRIVATE key value.
pub const IPC_PRIVATE: ShmKey = 0;

lazy_static! {
    /// Global shared memory manager instance.
    static ref SHM_MANAGER: Mutex<ShmManager> = Mutex::new(ShmManager::new());
}

