// Resource limits constants
const RLIMIT_DATA: u32 = 2;
const RLIMIT_STACK: u32 = 3;
const RLIMIT_NOFILE: u32 = 7;
const RLIMIT_MEMLOCK: u32 = 8;

// Default stack size (1MB)
const DEFAULT_STACK_SIZE: u64 = axconfig::TASK_STACK_SIZE as u64;
// Default file limit
const DEFAULT_FILE_LIMIT: u64 = 1024;
// Default core dump size (unlimited)
const DEFAULT_CORE_SIZE: u64 = u64::MAX;
// Default memory lock limit (64MB)
const DEFAULT_MEMLOCK_SIZE: u64 = 64 * 1024 * 1024;

/// Get resource limitations
///
/// TODO: support more resource types
pub fn sys_getrlimit(resource: c_int, rlimits: UserPtr<rlimit>) -> LinuxResult<isize> {
    debug!("sys_getrlimit <= resource: {}", resource);

    match resource as u32 {
        RLIMIT_DATA | RLIMIT_STACK | RLIMIT_NOFILE | RLIMIT_CORE | RLIMIT_MEMLOCK => {}
        _ => return Err(LinuxError::EINVAL),
    }

    let rlimit_val = rlimits.get_as_mut()?;

    match resource as u32 {
        RLIMIT_STACK => {
            rlimit_val.rlim_cur = DEFAULT_STACK_SIZE;
            rlimit_val.rlim_max = DEFAULT_STACK_SIZE;
        }
        RLIMIT_NOFILE => {
            rlimit_val.rlim_cur = DEFAULT_FILE_LIMIT;
            rlimit_val.rlim_max = DEFAULT_FILE_LIMIT;
        }
        RLIMIT_DATA => {
            // No specific limit for data segment
            rlimit_val.rlim_cur = u64::MAX;
            rlimit_val.rlim_max = u64::MAX;
        }
        RLIMIT_CORE => {
            // Allow core dumps with unlimited size
            rlimit_val.rlim_cur = DEFAULT_CORE_SIZE;
            rlimit_val.rlim_max = DEFAULT_CORE_SIZE;
        }
        RLIMIT_MEMLOCK => {
            // Allow memory locking with reasonable limit
            rlimit_val.rlim_cur = DEFAULT_MEMLOCK_SIZE;
            rlimit_val.rlim_max = DEFAULT_MEMLOCK_SIZE;
        }
        _ => {}
    }

    Ok(0)
}

/// Set resource limitations
///
/// TODO: support more resource types
pub fn sys_setrlimit(resource: c_int, rlimits: UserPtr<rlimit>) -> LinuxResult<isize> {
    debug!("sys_setrlimit <= resource: {}", resource);

    match resource as u32 {
        RLIMIT_DATA | RLIMIT_STACK | RLIMIT_NOFILE | RLIMIT_CORE | RLIMIT_MEMLOCK => {}
        _ => return Err(LinuxError::EINVAL),
    }

    // Validate the rlimits pointer but don't actually change limits
    let _rlimit_val = rlimits.get_as_mut()?;

    // Currently do not support setting resource limits
    // Just return success for compatibility
    Ok(0)
}

/// Get and/or set resource limitations for a specific process (or current process if pid is 0)
///
/// # Arguments
/// * `pid` - Process ID (0 means current process)
/// * `resource` - Resource type
/// * `new_limit` - New limit to set (can be null)
/// * `old_limit` - Buffer to store current limit (can be null)
///
/// # Returns
/// 0 on success
pub fn sys_prlimit64(
    pid: Pid,
    resource: c_int,
    new_limit: UserPtr<rlimit>,
    old_limit: UserPtr<rlimit>,
) -> LinuxResult<isize> {
    debug!("sys_prlimit64 <= pid: {}, resource: {}", pid, resource);

    // Validate resource type
    match resource as u32 {
        RLIMIT_DATA | RLIMIT_CORE | RLIMIT_STACK | RLIMIT_NOFILE | RLIMIT_MEMLOCK => {}
        _ => return Err(LinuxError::EINVAL),
    }

    // For now, only support current process (pid == 0) or current process ID
    // TODO: support other processes when we have proper process management
    if pid != 0 {
        // Get current process id and check if it matches
        let current_task = current();
        let current_pid = current_task.task_ext().thread.process().pid();
        if pid != current_pid {
            return Err(LinuxError::ESRCH); // No such process
        }
    }

    // If old_limit is provided, fill it with current limits
    if !old_limit.is_null() {
        let old_rlimit = old_limit.get_as_mut()?;
        match resource as u32 {
            RLIMIT_STACK => {
                old_rlimit.rlim_cur = DEFAULT_STACK_SIZE;
                old_rlimit.rlim_max = DEFAULT_STACK_SIZE;
            }
            RLIMIT_NOFILE => {
                old_rlimit.rlim_cur = DEFAULT_FILE_LIMIT;
                old_rlimit.rlim_max = DEFAULT_FILE_LIMIT;
            }
            RLIMIT_DATA => {
                old_rlimit.rlim_cur = u64::MAX;
                old_rlimit.rlim_max = u64::MAX;
            }
            RLIMIT_CORE => {
                old_rlimit.rlim_cur = DEFAULT_CORE_SIZE; // Allow core dumps
                old_rlimit.rlim_max = DEFAULT_CORE_SIZE; // Allow core dumps
            }
            RLIMIT_MEMLOCK => {
                old_rlimit.rlim_cur = DEFAULT_MEMLOCK_SIZE; // Memory lock limit
                old_rlimit.rlim_max = DEFAULT_MEMLOCK_SIZE; // Memory lock limit
            }
            _ => {}
        }
    }

    // If new_limit is provided, validate it but don't actually set it
    if !new_limit.is_null() {
        let _new_rlimit = new_limit.get_as_mut()?;
        // TODO: Actually set the new limits when we support it
        // For now, just validate the pointer and ignore the new values
    }

    Ok(0)
}

