/// Set and get file mode creation mask
///
/// # Arguments
/// * `mask` - New umask value (only the lower 9 bits are used)
///
/// # Returns
/// Previous umask value
pub fn sys_umask(mask: u32) -> LinuxResult<isize> {
    debug!("sys_umask <= mask: 0o{:o}", mask);

    let mut umask = UMASK.lock();
    let old_mask = *umask;

    // Only use the lower 9 bits (file permission bits)
    *umask = mask & 0o777;

    Ok(old_mask as isize)
}

/// Get current umask value (for internal use)
pub fn get_umask() -> u32 {
    *UMASK.lock()
}

