#[derive(Debug, Clone, Copy)]
pub struct Kstat {
    ino: u64,
    nlink: u32,
    uid: u32,
    gid: u32,
    mode: u32,
    size: u64,
    blocks: u64,
    blksize: u32,
}

impl Default for Kstat {
    fn default() -> Self {
        Self {
            ino: 1,
            nlink: 1,
            uid: 1,
            gid: 1,
            mode: 0,
            size: 0,
            blocks: 0,
            blksize: 4096,
        }
    }
}

impl Kstat {
    /// Creates a new Kstat with specified values, using defaults for others
    pub fn new(mode: u32, size: u64, blocks: u64, blksize: u32, nlink: u32) -> Self {
        Self {
            mode,
            size,
            blocks,
            blksize,
            nlink,
            ..Default::default()
        }
    }

    /// Get the size of the file
    pub fn size(&self) -> u64 {
        self.size
    }
}

impl From<Kstat> for stat {
    fn from(value: Kstat) -> Self {
        // SAFETY: valid for stat
        let mut stat: stat = unsafe { core::mem::zeroed() };
        stat.st_ino = value.ino as _;
        stat.st_nlink = value.nlink as _;
        stat.st_mode = value.mode as _;
        stat.st_uid = value.uid as _;
        stat.st_gid = value.gid as _;
        stat.st_size = value.size as _;
        stat.st_blksize = value.blksize as _;
        stat.st_blocks = value.blocks as _;

        stat
    }
}

impl From<Kstat> for statx {
    fn from(value: Kstat) -> Self {
        // SAFETY: valid for statx
        let mut statx: statx = unsafe { core::mem::zeroed() };
        statx.stx_blksize = value.blksize as _;
        statx.stx_attributes = value.mode as _;
        statx.stx_nlink = value.nlink as _;
        statx.stx_uid = value.uid as _;
        statx.stx_gid = value.gid as _;
        statx.stx_mode = value.mode as _;
        statx.stx_ino = value.ino as _;
        statx.stx_size = value.size as _;
        statx.stx_blocks = value.blocks as _;

        statx
    }
}

#[allow(dead_code)]
pub trait FileLike: Send + Sync {
    fn read(&self, buf: &mut [u8]) -> LinuxResult<usize>;
    fn write(&self, buf: &[u8]) -> LinuxResult<usize>;
    fn read_at(&self, offset: u64, buf: &mut [u8]) -> LinuxResult<usize> {
        let _ = offset;
        let _ = buf;
        Err(LinuxError::ESPIPE)
    }
    fn write_at(&self, offset: u64, buf: &[u8]) -> LinuxResult<usize> {
        let _ = offset;
        let _ = buf;
        Err(LinuxError::ESPIPE)
    }
    fn stat(&self) -> LinuxResult<Kstat>;
    fn truncate(&self, len: u64) -> LinuxResult {
        let _ = len;
        Err(LinuxError::EINVAL)
    }
    fn fsync(&self) -> LinuxResult {
        Err(LinuxError::EINVAL)
    }
    fn into_any(self: Arc<Self>) -> Arc<dyn Any + Send + Sync>;
    fn poll(&self) -> LinuxResult<PollState>;
    fn set_nonblocking(&self, nonblocking: bool) -> LinuxResult;

    fn from_fd(fd: c_int) -> LinuxResult<Arc<Self>>
    where
        Self: Sized + 'static,
    {
        get_file_like(fd)?
            .into_any()
            .downcast::<Self>()
            .map_err(|_| LinuxError::EINVAL)
    }

    fn add_to_fd_table(self) -> LinuxResult<c_int>
    where
        Self: Sized + 'static,
    {
        add_file_like(Arc::new(self))
    }
}

def_resource! {
    pub static FD_TABLE: ResArc<RwLock<FlattenObjects<Arc<dyn FileLike>, AX_FILE_LIMIT>>> = ResArc::new();
}

impl FD_TABLE {
    /// Return a copy of the inner table.
    pub fn copy_inner(&self) -> RwLock<FlattenObjects<Arc<dyn FileLike>, AX_FILE_LIMIT>> {
        let table = self.read();
        let mut new_table = FlattenObjects::new();
        for id in table.ids() {
            let _ = new_table.add_at(id, table.get(id).unwrap().clone());
        }
        RwLock::new(new_table)
    }

    pub fn clear(&self) {
        let mut table = self.write();
        let ids = table.ids().collect::<Vec<_>>();
        for id in ids {
            let _ = table.remove(id);
        }
    }

    /// Synchronize all open files in the file descriptor table.
    pub fn sync_all(&self) -> LinuxResult {
        let table = self.read();
        for id in table.ids() {
            if let Some(file) = table.get(id) {
                file.fsync()?;
            }
        }
        Ok(())
    }
}

/// Get a file-like object by `fd`.
pub fn get_file_like(fd: c_int) -> LinuxResult<Arc<dyn FileLike>> {
    FD_TABLE
        .read()
        .get(fd as usize)
        .cloned()
        .ok_or(LinuxError::EBADF)
}

/// Add a file to the file descriptor table.
pub fn add_file_like(f: Arc<dyn FileLike>) -> LinuxResult<c_int> {
    Ok(FD_TABLE.write().add(f).map_err(|_| LinuxError::EMFILE)? as c_int)
}

/// Close a file by `fd`.
pub fn close_file_like(fd: c_int) -> LinuxResult {
    let f = FD_TABLE
        .write()
        .remove(fd as usize)
        .ok_or(LinuxError::EBADF)?;
    debug!("close_file_like <= count: {}", Arc::strong_count(&f));
    Ok(())
}

#[ctor_bare::register_ctor]
fn init_stdio() {
    let mut fd_table = flatten_objects::FlattenObjects::new();
    fd_table
        .add_at(0, Arc::new(stdio::stdin()) as _)
        .unwrap_or_else(|_| panic!()); // stdin
    fd_table
        .add_at(1, Arc::new(stdio::stdout()) as _)
        .unwrap_or_else(|_| panic!()); // stdout
    fd_table
        .add_at(2, Arc::new(stdio::stdout()) as _)
        .unwrap_or_else(|_| panic!()); // stderr
    FD_TABLE.init_new(spin::RwLock::new(fd_table));
}

